	for orderIdx := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e308
		fallbackAssignIdx := -1

		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		existingLen := dispatch.AssignsLen

		for i := 0; i < max(existingLen+1, 1); i++ {
			if i == existingLen && i >= MAXASSIGNS {
				continue
			}

			isNewAssign := i >= existingLen
			currentAssign := &dispatch.Assigns[i]

			if isNewAssign {
				*currentAssign = Assign{}
			}

			oldStateValid := false
